#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <cstring>
#include <vector>
#include <omp.h>
#include "timing.h"

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define DEVICE   0
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

int platform_id_inuse = 0;
int device_id_inuse = 0;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    if (cols < 0 || rows < 0 || pyramid_height < 0)
    {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v] [-p platform_id] [-d device_id] [-t device_type]\n", argv[0]);
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
    {
        wall[n] = data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

static void dynproc_kernel_omp(int iteration,
                               const int* gpuWall,
                               const int* gpuSrc,
                               int* gpuResults,
                               int cols,
                               int rows_,
                               int startStep,
                               int border,
                               int halo_,
                               int BLOCK_SIZE,
                               int* outputBuffer,
                               int num_groups)
{
    (void)rows_;
    (void)halo_;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < num_groups; bx++)
    {
        int small_block_cols = BLOCK_SIZE - (iteration * HALO * 2);
        int blkX = (small_block_cols * bx) - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        vector<int> prev(BLOCK_SIZE, 0);
        vector<int> result_local(BLOCK_SIZE, 0);
        vector<unsigned char> isValid(BLOCK_SIZE, 0);
        vector<unsigned char> computed(BLOCK_SIZE, 0);

        for (int tx = 0; tx < BLOCK_SIZE; tx++)
        {
            int xidx = blkX + tx;
            isValid[tx] = IN_RANGE(tx, validXmin, validXmax) ? 1 : 0;
            if (IN_RANGE(xidx, 0, cols - 1))
            {
                prev[tx] = gpuSrc[xidx];
            }
        }

        for (int i = 0; i < iteration; i++)
        {
            for (int tx = 0; tx < BLOCK_SIZE; tx++)
            {
                computed[tx] = 0;
                int xidx = blkX + tx;

                if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid[tx])
                {
                    computed[tx] = 1;

                    int W = tx - 1;
                    int E = tx + 1;
                    W = (W < validXmin) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);

                    int index = cols * (startStep + i) + xidx;
                    result_local[tx] = shortest + gpuWall[index];

                    if (tx == 11 && i == 0)
                    {
                        int bufIndex = gpuSrc[xidx];
                        #pragma omp atomic write
                        outputBuffer[bufIndex] = 1;
                    }
                }
            }

            if (i == iteration - 1)
            {
                break;
            }

            for (int tx = 0; tx < BLOCK_SIZE; tx++)
            {
                if (computed[tx])
                {
                    prev[tx] = result_local[tx];
                }
            }
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++)
        {
            if (computed[tx])
            {
                int xidx = blkX + tx;
                gpuResults[xidx] = result_local[tx];
            }
        }
    }
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int size = rows * cols;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

    vector<int> gpuWall(size - cols);
    vector<int> gpuResult0(cols);
    vector<int> gpuResult1(cols);

    for (int i = 0; i < size - cols; i++) gpuWall[i] = data[cols + i];
    for (int i = 0; i < cols; i++) gpuResult0[i] = data[i];

    int gwsize = rows * cols;
    int BLOCK_SIZE = 256;
    if (BLOCK_SIZE > gwsize) BLOCK_SIZE = gwsize;
    while (BLOCK_SIZE > 1 && (gwsize % BLOCK_SIZE != 0)) BLOCK_SIZE--;
    if (BLOCK_SIZE < 1) BLOCK_SIZE = 1;
    int num_groups = gwsize / BLOCK_SIZE;

    int src = 1, final_ret = 0;
    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows - t - 1);
        int theHalo = HALO;

        const int* srcBuf = (src == 0) ? gpuResult0.data() : gpuResult1.data();
        int* dstBuf = (final_ret == 0) ? gpuResult0.data() : gpuResult1.data();

        dynproc_kernel_omp(arg0,
                           gpuWall.data(),
                           srcBuf,
                           dstBuf,
                           cols,
                           rows,
                           t,
                           borderCols,
                           theHalo,
                           BLOCK_SIZE,
                           h_outputBuffer,
                           num_groups);
    }

    int* finalBuf = (final_ret == 0) ? gpuResult0.data() : gpuResult1.data();
    for (int i = 0; i < cols; i++) result[i] = finalBuf[i];

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    free(h_outputBuffer);
    delete[] data;
    delete[] wall;
    delete[] result;

    return EXIT_SUCCESS;
}
